//考虑如下代码
if(X)
    if (Y) Foo();
else
z = 1;
//以上代码的else实际对应if(Y)分支，但由于编码形式的原因，
//（1）容易造成阅读代码时的困难，不确定else分支对应的是哪一个if
//（2）可能是潜在的逻辑错误，所期望的代码逻辑可能是else分支对应if(X)
//应将代码修改为：
if(X){
    if (Y){
        Foo();
    } 
}
else{
    z = 1;
}

